return msg;&#34;, &#34;outputs&#34;: 1, &#34;timeout&#34;: &#34;&#34;, &#34;noerr&#34;: 0, &#34;initialize&#34;: &#34;&#34;, &#34;finalize&#34;: &#34;&#34;, &#34;libs&#34;: [], &#34;x&#34;: 320, &#34;y&#34;: 120, &#34;wires&#34;: [ [ &#34;e474b6579589a570&#34;, &#34;ad4fcbed6335fb45&#34; ] ] }, { &#34;id&#34;: &#34;e474b6579589a570&#34;, &#34;type&#34;: &#34;http request&#34;, &#34;z&#34;: &#34;3117f04a786d98f3&#34;, &#34;g&#34;: &#34;52f6d3fda37eb850&#34;, &#34;name&#34;: &#34;Followers&#34;, &#34;method&#34;: &#34;GET&#34;, &#34;ret&#34;: &#34;obj&#34;, &#34;paytoqs&#34;: &#34;ignore&#34;, &#34;url&#34;: &#34;&#34;, &#34;tls&#34;: &#34;&#34;, &#34;persist&#34;: false, &#34;proxy&#34;: &#34;&#34;, &#34;insecureHTTPParser&#34;: false, &#34;authType&#34;: &#34;bearer&#34;, &#34;senderr&#34;: false, &#34;headers&#34;: [ { &#34;keyType&#34;: &#34;other&#34;, &#34;keyValue&#34;: &#34;Client-ID&#34;, &#34;valueType&#34;: &#34;other&#34;, &#34;valueValue&#34;: &#34;YOUR_CLIENT_ID&#34; }, { &#34;keyType&#34;: &#34;other&#34;, &#34;keyValue&#34;: &#34;Authorization&#34;, &#34;valueType&#34;: &#34;other&#34;, &#34;valueValue&#34;: &#34;Bearer YOUR_TOKEN&#34; } ], &#34;x&#34;: 510, &#34;y&#34;: 120, &#34;wires&#34;: [ [ &#34;2cc5ccf2675776dd&#34;, &#34;aa8044ccaabba288&#34; ] ] }, { &#34;id&#34;: &#34;2cc5ccf2675776dd&#34;, &#34;type&#34;: &#34;function&#34;, &#34;z&#34;: &#34;3117f04a786d98f3&#34;, &#34;g&#34;: &#34;52f6d3fda37eb850&#34;, &#34;name&#34;: &#34;Process followers&#34;, &#34;func&#34;: &#34;if (msg.payload &amp;&amp; msg.payload.total !== undefined) {
