;tostatus&#34;: false, &#34;complete&#34;: &#34;false&#34;, &#34;statusVal&#34;: &#34;&#34;, &#34;statusType&#34;: &#34;auto&#34;, &#34;x&#34;: 860, &#34;y&#34;: 260, &#34;wires&#34;: [] }, { &#34;id&#34;: &#34;4f857c3cac26b684&#34;, &#34;type&#34;: &#34;debug&#34;, &#34;z&#34;: &#34;3117f04a786d98f3&#34;, &#34;g&#34;: &#34;52f6d3fda37eb850&#34;, &#34;name&#34;: &#34;debug 4&#34;, &#34;active&#34;: true, &#34;tosidebar&#34;: true, &#34;console&#34;: false, &#34;tostatus&#34;: false, &#34;complete&#34;: &#34;false&#34;, &#34;statusVal&#34;: &#34;&#34;, &#34;statusType&#34;: &#34;auto&#34;, &#34;x&#34;: 380, &#34;y&#34;: 60, &#34;wires&#34;: [] }, { &#34;id&#34;: &#34;346df2a95aac5785&#34;, &#34;type&#34;: &#34;mqtt-broker&#34;, &#34;name&#34;: &#34;MQTT HA Broker&#34;, &#34;broker&#34;: &#34;IP_ADDRESS_MQTT_BROKER&#34;, &#34;port&#34;: &#34;1883&#34;, &#34;clientid&#34;: &#34;&#34;, &#34;autoConnect&#34;: true, &#34;usetls&#34;: false, &#34;protocolVersion&#34;: &#34;4&#34;, &#34;keepalive&#34;: &#34;60&#34;, &#34;cleansession&#34;: true, &#34;autoUnsubscribe&#34;: true, &#34;birthTopic&#34;: &#34;awtrix_prefix&#34;, &#34;birthQos&#34;: &#34;2&#34;, &#34;birthRetain&#34;: &#34;true&#34;, &#34;birthPayload&#34;: &#34;&#34;, &#34;birthMsg&#34;: {}, &#34;closeTopic&#34;: &#34;awtrix_prefix&#34;, &#34;closeQos&#34;: &#34;2&#34;, &#34;closeRetain&#34;: &#34;true&#34;, &#34;closePayload&#34;: &#34;&#34;, &#34;closeMsg&#34;: {}, &#34;willTopic&#34;: &#34;awtrix_prefix&#34;, &#34;willQos&#34;: &#34;2&#34;, &#34;willRetain&#34;: &#34;true&#34;, &#34;willPayload&#34;: &#34;&#34;, &#34;willMsg&#34;: {}, &#34;userProps&#34;: &#34;&#34;, &#34;sessionExpiry&#34;: &#34;&#34; } ] Zastosuj schemat Kliknij &ldquo;Deploy&rdquo; w prawym górnym rogu Node-RED, aby zastosować zmiany. Upewnij się, że wszystkie węzły są poprawnie skonfigurowane i połączone. Krok 4: Weryfikacja konfiguracji Ręczne wywołanie schematu
Ręcznie wywołaj węzeł inject, aby przetestować schemat. Sprawdź węzły debug, czy nie ma błędów lub wyników. Weryfikacja wiadomości MQTT
Upewnij się, że wiadomości MQTT są poprawnie wysyłane do twojego brokera. Postępując zgodnie z tymi krokami, pomyślnie utworzysz konto dewelopera Twitch, stworzysz aplikację, wygenerujesz token i zaimportujesz schemat Node-RED do interakcji z API Twitch.
